const fs = require('fs');
const data = $input.item.json;
const filename = (data.filename || data.fileName || data.title || data.name || data.titulo || 'Nota_Maia_Vazia').replace(/[^a-zA-Z0-9_.-]/g, '_');
const content = data.content || data.text || data.body || data.conteudo || data.texto || 'O agente esqueceu de mandar o texto.';
const path = '/Users/fsantoro/Desktop/Maia server/Knowledge_Base/02_Recursos/' + filename + '.md';

try {
  fs.writeFileSync(path, content, 'utf8');
  return { json: { success: true, file: filename + '.md', saved_content: content.substring(0, 50) + '...' } };
} catch (error) {
  return { json: { success: false, error: error.message } };
}
